import React from 'react';
import { View, Text, StyleSheet, SafeAreaView, ScrollView, StatusBar, Pressable, Switch, Alert } from 'react-native';
import { usePetStore } from '../stores/petStore';
import { useThemeStore } from '../stores/themeStore';
import { getColors, SPACING, FONT_SIZES, BORDER_RADIUS } from '../constants/theme';

interface SettingItemProps {
  icon: string;
  title: string;
  subtitle?: string;
  onPress?: () => void;
  rightElement?: React.ReactNode;
}

const SettingItem: React.FC<SettingItemProps> = ({ icon, title, subtitle, onPress, rightElement }) => (
  <Pressable style={styles.settingItem} onPress={onPress} disabled={!onPress}>
    <Text style={styles.settingIcon}>{icon}</Text>
    <View style={styles.settingContent}>
      <Text style={styles.settingTitle}>{title}</Text>
      {subtitle && <Text style={styles.settingSubtitle}>{subtitle}</Text>}
    </View>
    {rightElement}
  </Pressable>
);

interface SettingsScreenProps {
  onBack?: () => void;
}

export const SettingsScreen: React.FC<SettingsScreenProps> = ({ onBack }) => {
  const pet = usePetStore();
  const theme = useThemeStore();
  const COLORS = getColors(theme.isDarkMode);

  const handleReset = () => {
    Alert.alert(
      '重置宠物',
      '确定要重置宠物吗？所有进度将会丢失！',
      [
        { text: '取消', style: 'cancel' },
        { text: '确定', onPress: pet.reset, style: 'destructive' },
      ]
    );
  };

  const getDaysAlive = () => {
    const days = Math.floor((Date.now() - pet.createdAt) / (1000 * 60 * 60 * 24));
    return days;
  };

  return (
    <SafeAreaView style={[styles.container, { backgroundColor: COLORS.background }]}>
      <StatusBar barStyle={theme.isDarkMode ? "light-content" : "dark-content"} backgroundColor={COLORS.background} />
      <ScrollView>
        <View style={styles.header}>
          <Pressable onPress={onBack} style={styles.backButton}>
            <Text style={[styles.backText, { color: COLORS.primaryDark }]}>← 返回</Text>
          </Pressable>
          <Text style={[styles.title, { color: COLORS.primaryDark }]}>设置 ⚙️</Text>
          <View style={{ width: 60 }} />
        </View>

        <View style={styles.section}>
          <Text style={styles.sectionTitle}>外观</Text>
          <View style={[styles.card, { backgroundColor: COLORS.card }]}>
            <SettingItem
              icon="🌙"
              title="夜间模式"
              subtitle="切换深色/浅色主题"
              rightElement={<Switch value={theme.isDarkMode} onValueChange={theme.toggleDarkMode} trackColor={{ true: COLORS.primary }} />}
            />
          </View>
        </View>

        <View style={styles.section}>
          <Text style={styles.sectionTitle}>基本设置</Text>
          <View style={[styles.card, { backgroundColor: COLORS.card }]}>
            <SettingItem
              icon="🔊"
              title="音效"
              subtitle="操作时的声音反馈"
              rightElement={<Switch value={theme.soundEnabled} onValueChange={theme.toggleSound} trackColor={{ true: COLORS.primary }} />}
            />
            <SettingItem
              icon="📳"
              title="震动"
              subtitle="操作时的震动反馈"
              rightElement={<Switch value={theme.vibrationEnabled} onValueChange={theme.toggleVibration} trackColor={{ true: COLORS.primary }} />}
            />
            <SettingItem
              icon="🎵"
              title="背景音乐"
              subtitle="播放轻快的主题曲"
              rightElement={<Switch value={theme.bgmEnabled} onValueChange={theme.toggleBgm} trackColor={{ true: COLORS.primary }} />}
            />
          </View>
        </View>

        <View style={styles.section}>
          <Text style={styles.sectionTitle}>宠物管理</Text>
          <View style={[styles.card, { backgroundColor: COLORS.card }]}>
            <SettingItem
              icon="🔄"
              title="重置宠物"
              subtitle="重新开始养成"
              onPress={handleReset}
            />
          </View>
        </View>

        <View style={styles.section}>
          <Text style={styles.sectionTitle}>宠物信息</Text>
          <View style={[styles.card, { backgroundColor: COLORS.card }]}>
            <View style={styles.infoRow}>
              <Text style={[styles.infoLabel, { color: COLORS.text }]}>成长阶段</Text>
              <Text style={[styles.infoValue, { color: COLORS.primaryDark }]}>
                {pet.stage === 'baby' ? '🐕 幼年期' : 
                 pet.stage === 'young' ? '🐕‍🦺 青年期' : 
                 pet.stage === 'adult' ? '🦮 成年期' : '🐩 进化体'}
              </Text>
            </View>
            <View style={styles.infoRow}>
              <Text style={[styles.infoLabel, { color: COLORS.text }]}>存活天数</Text>
              <Text style={[styles.infoValue, { color: COLORS.primaryDark }]}>{getDaysAlive()} 天</Text>
            </View>
            <View style={styles.infoRow}>
              <Text style={[styles.infoLabel, { color: COLORS.text }]}>亲密度</Text>
              <Text style={[styles.infoValue, { color: COLORS.primaryDark }]}>{pet.intimacy}%</Text>
            </View>
          </View>
        </View>

        <View style={styles.section}>
          <Text style={styles.sectionTitle}>🐛 调试功能</Text>
          <View style={[styles.card, { backgroundColor: COLORS.card }]}>
            <View style={styles.infoRow}>
              <Text style={[styles.infoLabel, { color: COLORS.text }]}>虚拟年龄</Text>
              <Text style={[styles.infoValue, { color: COLORS.primaryDark }]}>
                {Math.floor((Date.now() - pet.createdAt) / (1000 * 60 * 60 * 24))} 天
              </Text>
            </View>
            <View style={styles.debugButtons}>
              <Pressable 
                style={[styles.debugButton, { backgroundColor: COLORS.primary }]}
                onPress={() => {
                  const newCreatedAt = pet.createdAt - (24 * 60 * 60 * 1000);
                  pet.setCreatedAt(newCreatedAt);
                }}
              >
                <Text style={styles.debugButtonText}>+1天</Text>
              </Pressable>
              <Pressable 
                style={[styles.debugButton, { backgroundColor: COLORS.primary }]}
                onPress={() => {
                  const newCreatedAt = pet.createdAt - (7 * 24 * 60 * 60 * 1000);
                  pet.setCreatedAt(newCreatedAt);
                }}
              >
                <Text style={styles.debugButtonText}>+7天</Text>
              </Pressable>
              <Pressable 
                style={[styles.debugButton, { backgroundColor: '#FF6B6B' }]}
                onPress={() => {
                  pet.evolve();
                }}
              >
                <Text style={styles.debugButtonText}>手动升级</Text>
              </Pressable>
            </View>
            <Text style={[styles.debugHint, { color: COLORS.textLight }]}>
              点击 +1天 / +7天 来模拟时间流逝，宠物将自动升级
            </Text>
          </View>
        </View>

        <View style={styles.section}>
          <Text style={styles.sectionTitle}>关于</Text>
          <View style={[styles.card, { backgroundColor: COLORS.card }]}>
            <SettingItem
              icon="📱"
              title="PetPal"
              subtitle="版本 1.0.0"
            />
            <SettingItem
              icon="💖"
              title="made with love"
              subtitle="为孩子们打造的电子宠物"
            />
          </View>
        </View>
      </ScrollView>
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: { flex: 1 },
  header: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', padding: SPACING.lg, paddingBottom: SPACING.sm },
  backButton: { padding: SPACING.xs },
  backText: { fontSize: FONT_SIZES.md, fontWeight: '600' },
  title: { fontSize: FONT_SIZES.xxl, fontWeight: 'bold' },
  section: { marginBottom: SPACING.lg, paddingHorizontal: SPACING.md },
  sectionTitle: { fontSize: FONT_SIZES.sm, color: '#888', marginBottom: SPACING.sm, marginLeft: SPACING.sm },
  card: { borderRadius: BORDER_RADIUS.lg, overflow: 'hidden' },
  settingItem: { flexDirection: 'row', alignItems: 'center', padding: SPACING.md, borderBottomWidth: 1, borderBottomColor: '#F0F0F0' },
  settingIcon: { fontSize: 24, marginRight: SPACING.md },
  settingContent: { flex: 1 },
  settingTitle: { fontSize: FONT_SIZES.md, fontWeight: '500' },
  settingSubtitle: { fontSize: FONT_SIZES.sm, color: '#888', marginTop: 2 },
  infoRow: { flexDirection: 'row', justifyContent: 'space-between', padding: SPACING.md, borderBottomWidth: 1, borderBottomColor: '#F0F0F0' },
  infoLabel: { fontSize: FONT_SIZES.md },
  infoValue: { fontSize: FONT_SIZES.md, fontWeight: '500' },
  debugButtons: { flexDirection: 'row', justifyContent: 'space-around', padding: SPACING.md, gap: 10 },
  debugButton: { flex: 1, paddingVertical: 10, paddingHorizontal: 16, borderRadius: 8, alignItems: 'center' },
  debugHint: { paddingHorizontal: SPACING.md, paddingBottom: SPACING.md, fontSize: FONT_SIZES.sm, textAlign: 'center' },
});
